import React, { useState, useMemo, createContext, useContext, useEffect } from 'react';
import { Routes, Route, Navigate, useLocation, HashRouter } from 'react-router-dom';
import { ThemeProvider, createTheme, CssBaseline } from '@mui/material';
import Layout from './components/layout/Layout';
import Dashboard from './pages/Dashboard';
import FileManager from './pages/FileManager';
import Visualizations from './pages/Visualizations';
import Settings from './pages/Settings';
import Help from './pages/Help';
import AboutUs from './pages/AboutUs';

// Create Theme Context
export const ColorModeContext = createContext({
  toggleColorMode: () => {},
  mode: 'light',
});

// Custom hook to use the color mode context
export const useColorMode = () => useContext(ColorModeContext);

function AppRoutes() {
  const location = useLocation();

  // Log current route for debugging
  useEffect(() => {
    console.log('Current route:', location.pathname);
  }, [location]);

  return (
    <Routes>
      <Route path="/dashboard" element={<Dashboard />} />
      <Route path="/files" element={<FileManager />} />
      <Route path="/visualizations" element={<Visualizations />} />
      <Route path="/settings" element={<Settings />} />
      <Route path="/help" element={<Help />} />
      <Route path="/about" element={<AboutUs />} />
      <Route path="/" element={<Navigate to="/dashboard" replace />} />
      <Route path="*" element={<Navigate to="/dashboard" replace />} />
    </Routes>
  );
}

function App() {
  // Initialize theme from localStorage or default to 'light'
  const [mode, setMode] = useState(() => {
    const savedMode = localStorage.getItem('themeMode');
    return savedMode || 'light';
  });

  // Update localStorage when theme changes
  useEffect(() => {
    localStorage.setItem('themeMode', mode);
  }, [mode]);

  const colorMode = useMemo(
    () => ({
      toggleColorMode: () => {
        setMode((prevMode) => {
          const newMode = prevMode === 'light' ? 'dark' : 'light';
          return newMode;
        });
      },
      mode,
    }),
    [mode]
  );

  // Create theme based on mode
  const theme = useMemo(
    () =>
      createTheme({
        palette: {
          mode,
          primary: {
            main: '#8E24AA', // Purple color from the design
            light: '#AB47BC',
            dark: '#7B1FA2',
            contrastText: '#FFFFFF',
          },
          secondary: {
            main: '#6200EA', // Deep purple for secondary actions
            light: '#7C4DFF',
            dark: '#4A148C',
            contrastText: '#FFFFFF',
          },
          background: {
            default: mode === 'light' ? '#F5F7FA' : '#121212',
            paper: mode === 'light' ? '#FFFFFF' : '#1E1E1E',
          },
          text: {
            primary: mode === 'light' ? '#1A1A1A' : '#FFFFFF',
            secondary: mode === 'light' ? '#575757' : '#B0B0B0',
          },
          info: {
            main: '#60A5FA', // Blue from design
          },
          success: {
            main: '#34D399', // Green from design
          },
          warning: {
            main: '#FBBF24', // Yellow from design
          },
          error: {
            main: '#F87171', // Red from design
          },
        },
        shape: {
          borderRadius: 12, // Rounded corners as seen in design
        },
        typography: {
          fontFamily: '"Inter", "Roboto", "Helvetica", "Arial", sans-serif',
          h1: {
            fontWeight: 600,
            fontSize: '2.5rem',
          },
          h2: {
            fontWeight: 600,
            fontSize: '2rem',
          },
          h3: {
            fontWeight: 600,
            fontSize: '1.75rem',
          },
          h4: {
            fontWeight: 600,
            fontSize: '1.5rem',
          },
          h5: {
            fontWeight: 600,
            fontSize: '1.25rem',
          },
          h6: {
            fontWeight: 600,
            fontSize: '1rem',
          },
          subtitle1: {
            fontWeight: 500,
            fontSize: '1rem',
          },
          subtitle2: {
            fontWeight: 500,
            fontSize: '0.875rem',
          },
          body1: {
            fontSize: '1rem',
          },
          body2: {
            fontSize: '0.875rem',
          },
        },
        components: {
          MuiButton: {
            styleOverrides: {
              root: {
                textTransform: 'none',
                borderRadius: 8,
                padding: '8px 16px',
                fontWeight: 500,
              },
              contained: {
                boxShadow: 'none',
                '&:hover': {
                  boxShadow: '0px 2px 4px rgba(0, 0, 0, 0.1)',
                },
              },
            },
          },
          MuiPaper: {
            styleOverrides: {
              root: {
                backgroundImage: 'none',
                boxShadow: mode === 'light' 
                  ? '0px 2px 8px rgba(0, 0, 0, 0.05)' 
                  : '0px 2px 8px rgba(0, 0, 0, 0.2)',
              },
              rounded: {
                borderRadius: 12,
              },
            },
          },
          MuiCard: {
            styleOverrides: {
              root: {
                overflow: 'hidden',
                borderRadius: 12,
              },
            },
          },
          MuiCardHeader: {
            styleOverrides: {
              root: {
                padding: '16px 20px',
              },
            },
          },
          MuiCardContent: {
            styleOverrides: {
              root: {
                padding: '16px 20px',
                '&:last-child': {
                  paddingBottom: 16,
                },
              },
            },
          },
          MuiListItem: {
            styleOverrides: {
              root: {
                borderRadius: 8,
              },
            },
          },
          MuiListItemButton: {
            styleOverrides: {
              root: {
                borderRadius: 8,
              },
            },
          },
          MuiTableCell: {
            styleOverrides: {
              root: {
                padding: '12px 16px',
                borderBottom: mode === 'light' 
                  ? '1px solid rgba(0, 0, 0, 0.08)' 
                  : '1px solid rgba(255, 255, 255, 0.08)',
              },
              head: {
                fontWeight: 600,
                color: mode === 'light' ? '#1A1A1A' : '#FFFFFF',
              },
            },
          },
          MuiInputBase: {
            styleOverrides: {
              root: {
                borderRadius: 8,
              },
            },
          },
          MuiOutlinedInput: {
            styleOverrides: {
              root: {
                borderRadius: 8,
              },
              notchedOutline: {
                borderColor: mode === 'light' 
                  ? 'rgba(0, 0, 0, 0.15)' 
                  : 'rgba(255, 255, 255, 0.15)',
              },
            },
          },
          MuiSelect: {
            styleOverrides: {
              outlined: {
                borderRadius: 8,
              },
            },
          },
          MuiAlert: {
            styleOverrides: {
              root: {
                borderRadius: 8,
              },
            },
          },
          MuiChip: {
            styleOverrides: {
              root: {
                borderRadius: 6,
              },
            },
          },
          MuiAppBar: {
            styleOverrides: {
              root: {
                boxShadow: 'none',
                borderBottom: mode === 'light' 
                  ? '1px solid rgba(0, 0, 0, 0.08)' 
                  : '1px solid rgba(255, 255, 255, 0.08)',
              },
            },
          },
          MuiDrawer: {
            styleOverrides: {
              paper: {
                borderRight: mode === 'light' 
                  ? '1px solid rgba(0, 0, 0, 0.08)' 
                  : '1px solid rgba(255, 255, 255, 0.08)',
              },
            },
          },
        },
      }),
    [mode]
  );

  return (
    <ColorModeContext.Provider value={colorMode}>
      <ThemeProvider theme={theme}>
        <CssBaseline />
        <HashRouter>
          <Layout>
            <AppRoutes />
          </Layout>
        </HashRouter>
      </ThemeProvider>
    </ColorModeContext.Provider>
  );
}

export default App;
